import postgres from 'postgres'

export async function ensureProfilesTable() {
  const host = `db.${process.env.NEXT_PUBLIC_SUPABASE_URL?.split('//')[1].split('.')[0]}.supabase.co`
  const sql = postgres({
    host,
    port: 5432,
    database: 'postgres',
    username: 'postgres',
    password: process.env.SUPABASE_DB_PASSWORD,
    ssl: 'require',
  })

  try {
    // Check if table exists
    const exists = await sql`
      SELECT EXISTS (
        SELECT FROM information_schema.tables 
        WHERE  table_schema = 'public'
        AND    table_name   = 'profiles'
      );
    `

    if (!exists[0].exists) {
      console.log('Creating profiles table...')
      
      await sql`
        CREATE TABLE public.profiles (
          id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
          full_name TEXT NOT NULL,
          email TEXT NOT NULL,
          mobile_number TEXT,
          aadhaar_number TEXT,
          role TEXT NOT NULL CHECK (role IN ('citizen', 'government', 'media')),
          government_identity TEXT,
          media_organization TEXT,
          created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
        );
      `

      await sql`ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;`
      
      // Policies
      await sql`
        DO $$
        BEGIN
            IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Public profiles are viewable by everyone.') THEN
                CREATE POLICY "Public profiles are viewable by everyone." ON public.profiles FOR SELECT USING (true);
            END IF;
            IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can insert their own profile.') THEN
                CREATE POLICY "Users can insert their own profile." ON public.profiles FOR INSERT WITH CHECK (auth.uid() = id);
            END IF;
            IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can update own profile.') THEN
                CREATE POLICY "Users can update own profile." ON public.profiles FOR UPDATE USING (auth.uid() = id);
            END IF;
        END
        $$;
      `
      
      console.log('Profiles table created successfully.')
    }
  } catch (error) {
    console.error('Error ensuring profiles table:', error)
    throw error
  } finally {
    await sql.end()
  }
}
